pair A, B, C, M, O;

A = (0,4);
B = (-3,0);
C = (3,0);
O = circumcenter(A,B,C);
M = (B + C)/2;

draw(A--B--C--cycle);
draw(circumcircle(A,B,C));
draw(B--O--C);
draw(A--M);

